-- Núcleo SAP-like: controladoria, fechamento, conciliação e estoque enterprise.
CREATE TABLE IF NOT EXISTS "periodos_financeiros" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "ano" INTEGER NOT NULL, "mes" INTEGER NOT NULL, "status" TEXT NOT NULL DEFAULT 'ABERTO', "fechadoEm" TIMESTAMP(3), "fechadoPor" TEXT, "observacao" TEXT, "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "atualizadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE UNIQUE INDEX IF NOT EXISTS "periodos_financeiros_empresaId_filialId_ano_mes_key" ON "periodos_financeiros"("empresaId", "filialId", "ano", "mes");
CREATE INDEX IF NOT EXISTS "periodos_financeiros_empresaId_idx" ON "periodos_financeiros"("empresaId");
CREATE INDEX IF NOT EXISTS "periodos_financeiros_filialId_idx" ON "periodos_financeiros"("filialId");
CREATE TABLE IF NOT EXISTS "lancamentos_contabeis" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "dataCompetencia" TIMESTAMP(3) NOT NULL, "dataCaixa" TIMESTAMP(3), "origem" TEXT NOT NULL, "referenciaId" TEXT, "contaDebitoId" TEXT, "contaCreditoId" TEXT, "centroCustoId" TEXT, "historico" TEXT NOT NULL, "valor" DECIMAL(12,2) NOT NULL, "estornado" BOOLEAN NOT NULL DEFAULT false, "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "lancamentos_contabeis_empresaId_idx" ON "lancamentos_contabeis"("empresaId");
CREATE INDEX IF NOT EXISTS "lancamentos_contabeis_filialId_idx" ON "lancamentos_contabeis"("filialId");
CREATE INDEX IF NOT EXISTS "lancamentos_contabeis_dataCompetencia_idx" ON "lancamentos_contabeis"("dataCompetencia");
CREATE INDEX IF NOT EXISTS "lancamentos_contabeis_origem_idx" ON "lancamentos_contabeis"("origem");
CREATE TABLE IF NOT EXISTS "conciliacoes_bancarias" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "banco" TEXT NOT NULL, "agencia" TEXT, "conta" TEXT, "dataExtrato" TIMESTAMP(3) NOT NULL, "descricao" TEXT NOT NULL, "valor" DECIMAL(12,2) NOT NULL, "tipo" TEXT NOT NULL, "movimentoCaixaId" TEXT, "status" TEXT NOT NULL DEFAULT 'PENDENTE', "conciliadoEm" TIMESTAMP(3), "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "atualizadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "conciliacoes_bancarias_empresaId_idx" ON "conciliacoes_bancarias"("empresaId"); CREATE INDEX IF NOT EXISTS "conciliacoes_bancarias_filialId_idx" ON "conciliacoes_bancarias"("filialId"); CREATE INDEX IF NOT EXISTS "conciliacoes_bancarias_status_idx" ON "conciliacoes_bancarias"("status"); CREATE INDEX IF NOT EXISTS "conciliacoes_bancarias_dataExtrato_idx" ON "conciliacoes_bancarias"("dataExtrato");
CREATE TABLE IF NOT EXISTS "contas_recorrentes" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "tipo" TEXT NOT NULL, "descricao" TEXT NOT NULL, "valor" DECIMAL(12,2) NOT NULL, "diaVencimento" INTEGER NOT NULL, "centroCustoId" TEXT, "contaContabilId" TEXT, "ativo" BOOLEAN NOT NULL DEFAULT true, "proximaGeracao" TIMESTAMP(3), "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "atualizadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "contas_recorrentes_empresaId_idx" ON "contas_recorrentes"("empresaId"); CREATE INDEX IF NOT EXISTS "contas_recorrentes_filialId_idx" ON "contas_recorrentes"("filialId"); CREATE INDEX IF NOT EXISTS "contas_recorrentes_tipo_idx" ON "contas_recorrentes"("tipo");
CREATE TABLE IF NOT EXISTS "aprovacoes_pagamento" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "contaPagarId" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'PENDENTE', "solicitadoPor" TEXT, "aprovadoPor" TEXT, "aprovadoEm" TIMESTAMP(3), "motivo" TEXT, "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "atualizadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "aprovacoes_pagamento_empresaId_idx" ON "aprovacoes_pagamento"("empresaId"); CREATE INDEX IF NOT EXISTS "aprovacoes_pagamento_filialId_idx" ON "aprovacoes_pagamento"("filialId"); CREATE INDEX IF NOT EXISTS "aprovacoes_pagamento_contaPagarId_idx" ON "aprovacoes_pagamento"("contaPagarId"); CREATE INDEX IF NOT EXISTS "aprovacoes_pagamento_status_idx" ON "aprovacoes_pagamento"("status");
CREATE TABLE IF NOT EXISTS "reservas_estoque" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "produtoId" TEXT NOT NULL, "origem" TEXT NOT NULL, "referenciaId" TEXT, "quantidade" INTEGER NOT NULL, "status" TEXT NOT NULL DEFAULT 'ATIVA', "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "atualizadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "reservas_estoque_empresaId_idx" ON "reservas_estoque"("empresaId"); CREATE INDEX IF NOT EXISTS "reservas_estoque_filialId_idx" ON "reservas_estoque"("filialId"); CREATE INDEX IF NOT EXISTS "reservas_estoque_produtoId_idx" ON "reservas_estoque"("produtoId"); CREATE INDEX IF NOT EXISTS "reservas_estoque_status_idx" ON "reservas_estoque"("status");
CREATE TABLE IF NOT EXISTS "inventarios_estoque" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "tipo" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'ABERTO', "descricao" TEXT, "iniciadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "encerradoEm" TIMESTAMP(3), "criadoPor" TEXT, "aprovadoPor" TEXT);
CREATE INDEX IF NOT EXISTS "inventarios_estoque_empresaId_idx" ON "inventarios_estoque"("empresaId"); CREATE INDEX IF NOT EXISTS "inventarios_estoque_filialId_idx" ON "inventarios_estoque"("filialId"); CREATE INDEX IF NOT EXISTS "inventarios_estoque_status_idx" ON "inventarios_estoque"("status");
CREATE TABLE IF NOT EXISTS "itens_inventario_estoque" ("empresaId" TEXT, "filialId" TEXT, "id" TEXT PRIMARY KEY, "inventarioId" TEXT NOT NULL, "produtoId" TEXT NOT NULL, "estoqueSistema" INTEGER NOT NULL, "estoqueContado" INTEGER NOT NULL, "divergencia" INTEGER NOT NULL, "status" TEXT NOT NULL DEFAULT 'PENDENTE', "observacao" TEXT, "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "itens_inventario_estoque_empresaId_idx" ON "itens_inventario_estoque"("empresaId"); CREATE INDEX IF NOT EXISTS "itens_inventario_estoque_filialId_idx" ON "itens_inventario_estoque"("filialId"); CREATE INDEX IF NOT EXISTS "itens_inventario_estoque_inventarioId_idx" ON "itens_inventario_estoque"("inventarioId"); CREATE INDEX IF NOT EXISTS "itens_inventario_estoque_produtoId_idx" ON "itens_inventario_estoque"("produtoId");
CREATE TABLE IF NOT EXISTS "transferencias_estoque" ("empresaId" TEXT, "filialOrigemId" TEXT, "filialDestinoId" TEXT, "id" TEXT PRIMARY KEY, "produtoId" TEXT NOT NULL, "quantidade" INTEGER NOT NULL, "status" TEXT NOT NULL DEFAULT 'PENDENTE_SAIDA', "observacao" TEXT, "enviadoEm" TIMESTAMP(3), "recebidoEm" TIMESTAMP(3), "criadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "atualizadoEm" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE INDEX IF NOT EXISTS "transferencias_estoque_empresaId_idx" ON "transferencias_estoque"("empresaId"); CREATE INDEX IF NOT EXISTS "transferencias_estoque_filialOrigemId_idx" ON "transferencias_estoque"("filialOrigemId"); CREATE INDEX IF NOT EXISTS "transferencias_estoque_filialDestinoId_idx" ON "transferencias_estoque"("filialDestinoId"); CREATE INDEX IF NOT EXISTS "transferencias_estoque_produtoId_idx" ON "transferencias_estoque"("produtoId"); CREATE INDEX IF NOT EXISTS "transferencias_estoque_status_idx" ON "transferencias_estoque"("status");
